() => {
  function getXPath(el) {
    if (!el) return null;
    if (el.id) return '//*[@id="' + el.id + '"]';

    const parts = [];
    while (el && el.nodeType === Node.ELEMENT_NODE) {
      let index = 1;
      let sibling = el.previousElementSibling;

      while (sibling) {
        if (sibling.nodeName === el.nodeName) index++;
        sibling = sibling.previousElementSibling;
      }

      parts.unshift(el.nodeName.toLowerCase() + "[" + index + "]");
      el = el.parentElement;
    }

    return "/" + parts.join("/");
  }

  // Extract conference name
  const conferenceName = document.querySelector('h1')?.textContent?.trim() || null;

  // Extract acronym and dates from h2
  const h2Text = document.querySelector('h2')?.textContent?.trim() || '';
  const acronymMatch = h2Text.match(/ICOA\d+/);
  const acronym = acronymMatch ? acronymMatch[0] : null;

  // Extract location and dates from h4
  const h4Text = document.querySelector('h4')?.textContent?.trim() || '';
  const locationMatch = h4Text.match(/,\s*(.+)$/);
  const location = h4Text || null;
  const datesMatch = h4Text.match(/^([\d\-]+\s+\w+\s+\d{4})/);
  const conferenceDates = datesMatch ? datesMatch[1] : null;

  // Look for submission deadline and notification date
  let submissionDeadline = null;
  let notificationDate = null;
  let submissionUrl = null;
  let deadlineElement = null;

  // Search for deadline information in the page
  const allText = document.body.innerText;
  const deadlineMatch = allText.match(/submission\s+deadline[:\s]+([^\n]+)/i);
  const notificationMatch = allText.match(/notification[:\s]+([^\n]+)/i);

  if (deadlineMatch) submissionDeadline = deadlineMatch[1].trim();
  if (notificationMatch) notificationDate = notificationMatch[1].trim();

  // Look for submission section
  const submissionSection = document.querySelector('#submission');
  if (submissionSection) {
    const submissionText = submissionSection.innerText;

    // Try to find deadline in submission section
    const deadlineInSection = submissionText.match(/deadline[:\s]+([^\n]+)/i);
    if (deadlineInSection) {
      submissionDeadline = deadlineInSection[1].trim();
      // Find the element containing deadline
      const elements = submissionSection.querySelectorAll('*');
      for (let el of elements) {
        if (el.innerText && el.innerText.toLowerCase().includes('deadline')) {
          deadlineElement = el;
          break;
        }
      }
    }

    // Look for submission URL
    const submissionLink = submissionSection.querySelector('a[href*="submit"], a[href*="easychair"], a[href*="cmt"]');
    if (submissionLink) {
      submissionUrl = submissionLink.href;
    }
  }

  // Extract topics
  const topics = [];
  const topicsSection = document.querySelector('#topics, [id*="topic"]');
  if (topicsSection) {
    const listItems = topicsSection.querySelectorAll('li');
    listItems.forEach(li => {
      const topic = li.textContent.trim();
      if (topic) topics.push(topic);
    });
  }

  // If no deadline element found yet, search more broadly
  if (!deadlineElement) {
    const allElements = document.querySelectorAll('*');
    for (let el of allElements) {
      const text = el.textContent;
      if (text && (text.includes('deadline') || text.includes('Deadline')) && el.children.length < 5) {
        deadlineElement = el;
        break;
      }
    }
  }

  // Get XPath for the main section containing dates/deadlines
  let sourceXpath = null;
  if (deadlineElement) {
    sourceXpath = getXPath(deadlineElement);
  } else {
    // Use the main header section as fallback
    const mainSection = document.querySelector('h4');
    if (mainSection) {
      sourceXpath = getXPath(mainSection);
    }
  }

  return {
    conferenceName,
    acronym,
    submissionDeadline,
    notificationDate,
    conferenceDates,
    location,
    topics,
    submissionUrl,
    sourceXpath,
    bodyText: allText.substring(0, 2000) // First 2000 chars for inspection
  };
}

