    const fieldsSection = Array.from(topicsSection.querySelectorAll('h4')).find(h => h.textContent.includes('FIELDS AND AREAS'));
    if (fieldsSection && fieldsSection.nextElementSibling) {
      const fieldsText = fieldsSection.nextElementSibling.textContent;
