() => {
  function getXPath(el) {
    if (!el) return null;
    if (el.id) return '//*[@id="' + el.id + '"]';

    const parts = [];
    while (el && el.nodeType === Node.ELEMENT_NODE) {
      let index = 1;
      let sibling = el.previousElementSibling;

      while (sibling) {
        if (sibling.nodeName === el.nodeName) index++;
        sibling = sibling.previousElementSibling;
      }

      parts.unshift(el.nodeName.toLowerCase() + "[" + index + "]");
      el = el.parentElement;
    }

    return "/" + parts.join("/");
  }

  // Extract topics more carefully
  const topics = [];

  // Find all h4 headings in the submission section
  const h4Elements = document.querySelectorAll('h4');

  let collectTopics = false;
  let currentSection = null;

  h4Elements.forEach(h4 => {
    const text = h4.textContent.trim();

    if (text === 'TOOLS AND METHODS' || text === 'FIELDS AND AREAS') {
      collectTopics = true;
      currentSection = h4;

      // Get the next sibling div that contains the topics
      let nextEl = h4.nextElementSibling;
      while (nextEl) {
        if (nextEl.tagName === 'DIV') {
          // Get all text nodes from this div
          const divText = nextEl.textContent;
          const lines = divText.split('\n').map(l => l.trim()).filter(l => l.length > 0);
          topics.push(...lines);
          break;
        }
        nextEl = nextEl.nextElementSibling;
      }
    } else if (text === 'Submission Guidelines') {
      collectTopics = false;
    }
  });

  // Also try to get topics from the visible text
  const submissionSection = document.querySelector('#submission');
  if (submissionSection && topics.length === 0) {
    const allDivs = submissionSection.querySelectorAll('div');

    allDivs.forEach(div => {
      const parent = div.parentElement;
      const prevSibling = div.previousElementSibling;

      if (prevSibling && prevSibling.tagName === 'H4') {
        const h4Text = prevSibling.textContent.trim();
        if (h4Text === 'TOOLS AND METHODS' || h4Text === 'FIELDS AND AREAS') {
          const lines = div.textContent.split('\n').map(l => l.trim()).filter(l => l.length > 0 && l.length < 100);
          topics.push(...lines);
        }
      }
    });
  }

  return {
    topics: [...new Set(topics)], // Remove duplicates
    topicsCount: topics.length
  };
}

() => {
  // Get all text content from the page
  const bodyText = document.body.innerText;

  // Find the section with topics
  const toolsIndex = bodyText.indexOf('TOOLS AND METHODS');
  const fieldsIndex = bodyText.indexOf('FIELDS AND AREAS');
  const guidelinesIndex = bodyText.indexOf('Submission Guidelines');

  const topics = [];

  if (toolsIndex !== -1 && fieldsIndex !== -1) {
    // Extract tools section
    const toolsSection = bodyText.substring(toolsIndex, fieldsIndex);
    const toolsLines = toolsSection.split('\n').map(l => l.trim()).filter(l => l && l !== 'TOOLS AND METHODS');
    topics.push(...toolsLines);

    // Extract fields section
    const fieldsSection = bodyText.substring(fieldsIndex, guidelinesIndex !== -1 ? guidelinesIndex : bodyText.length);
    const fieldsLines = fieldsSection.split('\n').map(l => l.trim()).filter(l => l && l !== 'FIELDS AND AREAS');
    topics.push(...fieldsLines);
  }

  return {
    topics: topics.filter(t => t.length > 3 && t.length < 100),
    toolsIndex,
    fieldsIndex,
    guidelinesIndex
  };
}

